import { Component, CUSTOM_ELEMENTS_SCHEMA } from '@angular/core';
import { CommonModule } from '@angular/common';
import { FormsModule } from '@angular/forms';

@Component({
  selector: 'app-chat',
  standalone: true,
  imports: [CommonModule, FormsModule],
  schemas: [CUSTOM_ELEMENTS_SCHEMA],
  templateUrl: './chat.component.html',
  styleUrls: ['./chat.component.scss']
})
export class ChatComponent {
  inputText: string = '';

  // Suggestions de l'interface d'accueil
  suggestions = [
    { title: "Consulter les factures", desc: "Afficher les derniers impayés", icon: 'file-text', iconColor: 'text-amber-400' },
    { title: "Faire un transfert", desc: "Transférer des fonds ou un virement", icon: 'refresh-cw', iconColor: 'text-purple-400' },
    { title: "Vérifier un débit", desc: "Analyser une opération sortante", icon: 'credit-card', iconColor: 'text-blue-400' },
    { title: "Support Multilingue", desc: "Parler en n'importe quelle langue", icon: 'globe', iconColor: 'text-emerald-400' },
  ];

  sendMessage() {
    if (!this.inputText.trim()) return;
    
    console.log("Texte envoyé à l'agent DWEXO :", this.inputText);
    this.inputText = '';
  }

  selectSuggestion(title: string) {
    this.inputText = `Je souhaite ${title.toLowerCase()}`;
  }
}
